# %% ../../../nbs/audio.datasets.tts.ipynb 5
class LhotseTTSDataset(Dataset):
    def __init__(self,
                tokenizer:TokenCollater, # text tokenizer
                extractor=OnTheFlyFeatures(Fbank(FbankConfig(num_mel_bins=80))) # feature extractor
                ):
        self.extractor = extractor
        self.tokenizer = tokenizer

    def __getitem__(self, cuts: CutSet) -> Dict[str, torch.Tensor]:
        cuts = cuts.sort_by_duration()
        feats, feat_lens = self.extractor(cuts)
        tokens, token_lens = self.tokenizer(cuts)
        return {"feats": feats, "feats_lens": feat_lens, "tokens": tokens, "tokens_lens": token_lens}

# %% ../../../nbs/audio.datasets.tts.ipynb 15
class LibriTTSDataModule(LightningDataModule):
    def __init__(self,
        target_dir="/data/en/libriTTS", # where data will be saved / retrieved
        dataset_parts=["dev-clean", "test-clean"], # either full libritts or subset
        output_dir="/home/syl20/slg/nimrod/recipes/libritts/data", # where to save manifest
        num_jobs=1, # num_jobs depending on number of cpus available
        tokenizer=TokenCollater,
        extractor=OnTheFlyFeatures(Fbank(FbankConfig(sampling_rate=24000, num_mel_bins=80)))
        
    ):
        super().__init__()
        self.save_hyperparameters(logger=False)
        self.tokenizer = tokenizer
        self.extractor = extractor

    def prepare_data(self,) -> None:
        # takes a while to download from openslr mirror (~15 min each for test/dev-clean)
        download_libritts(target_dir=self.hparams.target_dir, dataset_parts=self.hparams.dataset_parts)

    def setup(self, stage = None):
        self.libri = prepare_libritts(corpus_dir=Path(self.hparams.target_dir) / "LibriTTS", output_dir=self.hparams.output_dir, num_jobs=self.hparams.num_jobs)
        if stage == 'fit' or stage == None:
            self.cuts_train = CutSet.from_manifests(**self.libri["dev-clean"])
            self.cuts_test = CutSet.from_manifests(**self.libri["test-clean"])
            self.tokenizer = self.tokenizer(self.cuts_train)
            self.tokenizer(self.cuts_test.subset(first=2))
            # self.tokenizer.inverse(*self.tokenizer(self.cuts_test.subset(first=2)))
        if stage == "test":
            self.cuts_test = CutSet.from_manifests(**self.libri["test-clean"])
            self.tokenizer = self.tokenizer(self.cuts_test)
            self.tokenizer(self.cuts_test.subset(first=2))
            # self.tokenizer.inverse(*self.tokenizer(self.cuts_test.subset(first=2)))

    def train_dataloader(self):
        train_sampler = BucketingSampler(self.cuts_train, max_duration=300, shuffle=True, bucket_method="equal_duration")
        return DataLoader(LhotseTTSDataset(tokenizer=self.tokenizer, extractor=self.extractor), sampler=train_sampler, batch_size=None, num_workers=1)

    def test_dataloader(self):
        test_sampler = BucketingSampler(self.cuts_test, max_duration=400, shuffle=False, bucket_method="equal_duration")
        return DataLoader(LhotseTTSDataset(tokenizer=self.tokenizer, extractor=self.extractor), sampler=test_sampler, batch_size=None, num_workers=1)

    @property
    def model_kwargs(self):
        return {
            "odim": len(self.tokenizer.idx2token),
        }

# %% ../../../nbs/audio.datasets.tts.ipynb 28
class LJSpeechTTSDataModule(LightningDataModule):
    def __init__(self,
        target_dir="../data/en", # where data will be saved / retrieved
        output_dir="../recipes/tts/ljspeech/data_test", # where to save manifest
        tokenizer=TokenCollater,
        extractor=OnTheFlyFeatures(Fbank(FbankConfig(sampling_rate=22050, num_mel_bins=80))),
        offline_compute=False,
        num_jobs=1,
        max_duration=300,
        num_buckets=10,
        shuffle=True,
    ):
        super().__init__()
        self.save_hyperparameters(logger=False)
        self._tokenizer = tokenizer
        self.extractor = extractor
        self.unique_phonemes = set()

    def prepare_data(self,) -> None:
        # takes a while to download from openslr mirror (~15 min each for test/dev-clean)
        download_ljspeech(target_dir=self.hparams.target_dir)

    def setup(self, stage = None):
        logger.info("setup")

        self.data = prepare_ljspeech(corpus_dir=Path(self.hparams.target_dir) / "LJSpeech-1.1", output_dir=self.hparams.output_dir)
        cut_set = CutSet.from_manifests(**self.data)
        if isinstance(self.extractor, PrecomputedFeatures) and self.hparams.offline_compute:
            logger.info("compute features offline")
            extractor = EncoDecExtractor()
            cut_set = cut_set.compute_and_store_features(
                extractor=extractor,
                storage_path=self.hparams.output_dir,
                num_jobs=self.hparams.num_jobs,
            )

        if self._tokenizer == PhonemeCollater:
            logger.info("extract phonemes from text")
            cleaner = TTSTextNormalizer()
            phonemizer = Phonemizer()
            
            for cut in cut_set:
               text = cut.supervisions[0].text
               normalized = cleaner(text)
               phonemes = phonemizer(text)
               print(phonemes)
               cut.custom = {'normalized': normalized, 'phonemes': phonemes}
               self.unique_phonemes.update(list(phonemes))
        
        self.cut_train  = cut_set.subset(first=12500)
        cut_dev_test = cut_set.subset(last=600)
        self.cut_test = cut_dev_test.subset(last=400)
        self.cut_dev = cut_dev_test.subset(first=200)

        if stage == 'fit' or stage == None:
            self._tokenizer = self._tokenizer(self.cut_train)
            self._tokenizer(self.cut_test.subset(first=2))
            # self.tokenizer.inverse(*self.tokenizer(self.cuts_test.subset(first=2)))
        if stage == "test":
            self._tokenizer = self._tokenizer(self.cut_test)
            self._tokenizer(self.cut_test.subset(first=2))
            # self.tokenizer.inverse(*self.tokenizer(self.cuts_test.subset(first=2)))

    def train_dataloader(self):
        train_sampler = BucketingSampler(self.cut_train, num_buckets=self.hparams.num_buckets, max_duration=self.hparams.max_duration, shuffle=self.hparams.shuffle, bucket_method="equal_duration")
        return DataLoader(LhotseTTSDataset(self._tokenizer, self.extractor), sampler=train_sampler, batch_size=None, num_workers=1)

    def test_dataloader(self):
        test_sampler = BucketingSampler(self.cut_test, num_buckets=self.hparams.num_buckets, max_duration=self.hparams.max_duration, shuffle=self.hparams.shuffle, bucket_method="equal_duration")
        return DataLoader(LhotseTTSDataset(self._tokenizer, self.extractor), sampler=test_sampler, batch_size=None, num_workers=1)

    @property
    def model_kwargs(self):
        return {
            "odim": len(self._tokenizer.idx2token),
        }

    @property
    def tokenizer(self):
        return(self._tokenizer)
    
    @property
    def phonemes(self):
        return(self.unique_phonemes)
